Implement the `TlsAcceptor` and `TlsAcceptorBuilder` for server-side TLS connections.

## Rationale

Server TLS is required for:
- HTTPS servers
- gRPC servers
- WebSocket secure (wss://) servers
- Any service accepting secure connections

## Implementation

### TlsAcceptor

```rust
// tls/src/acceptor.rs

use std::sync::Arc;
use std::path::Path;
use rustls::{ServerConfig, ServerConnection};

use crate::{Certificate, CertificateChain, PrivateKey, RootCertStore, TlsError, TlsStream};

/// Server-side TLS acceptor.
///
/// This is typically configured once and reused to accept many connections.
pub struct TlsAcceptor {
    config: Arc<ServerConfig>,
}

impl TlsAcceptor {
    /// Create from a raw rustls ServerConfig.
    pub fn new(config: ServerConfig) -> Self {
        TlsAcceptor {
            config: Arc::new(config),
        }
    }

    /// Create a builder for constructing a TlsAcceptor.
    pub fn builder(chain: CertificateChain, key: PrivateKey) -> TlsAcceptorBuilder {
        TlsAcceptorBuilder::new(chain, key)
    }

    /// Accept a TLS connection, performing the handshake.
    ///
    /// # Cancel-Safety
    /// This method is NOT cancel-safe during handshake. If cancelled mid-handshake,
    /// the connection is in an undefined state and should be dropped.
    pub async fn accept<IO>(
        &self,
        stream: IO,
    ) -> Result<TlsStream<IO>, TlsError>
    where
        IO: AsyncRead + AsyncWrite + Unpin,
    {
        tracing::debug!("Starting TLS accept handshake");

        let conn = ServerConnection::new(self.config.clone())
            .map_err(|e| TlsError::Handshake(e.to_string()))?;

        let mut tls_stream = TlsStream::new_server(stream, conn);

        // Perform the handshake
        tls_stream.handshake().await?;

        tracing::info!(
            protocol = ?tls_stream.protocol_version(),
            alpn = ?tls_stream.alpn_protocol(),
            sni = ?tls_stream.sni_hostname(),
            "TLS accept complete"
        );

        Ok(tls_stream)
    }

    /// Get the inner config (for advanced use).
    pub fn config(&self) -> &Arc<ServerConfig> {
        &self.config
    }
}

impl Clone for TlsAcceptor {
    fn clone(&self) -> Self {
        TlsAcceptor {
            config: self.config.clone(),
        }
    }
}
