### Certificate Helper Types

```rust
// tls/src/certs.rs

use std::path::Path;

/// X.509 certificate.
#[derive(Clone)]
pub struct Certificate(pub(crate) Vec<u8>);

impl Certificate {
    /// Parse certificates from PEM data.
    pub fn from_pem(pem: &[u8]) -> Result<Vec<Self>, TlsError> {
        let mut certs = Vec::new();
        let mut reader = std::io::BufReader::new(pem);

        for cert in rustls_pemfile::certs(&mut reader)
            .map_err(|e| TlsError::Certificate(e.to_string()))?
        {
            certs.push(Certificate(cert.to_vec()));
        }

        if certs.is_empty() {
            return Err(TlsError::Certificate("no certificates found in PEM".into()));
        }

        tracing::debug!(count = certs.len(), "Parsed PEM certificates");
        Ok(certs)
    }

    /// Create from DER data.
    pub fn from_der(der: &[u8]) -> Self {
        Certificate(der.to_vec())
    }

    /// Load from PEM file.
    pub fn from_pem_file(path: impl AsRef<Path>) -> Result<Vec<Self>, TlsError> {
        let pem = std::fs::read(path.as_ref())
            .map_err(|e| TlsError::Certificate(format!("reading file: {}", e)))?;
        Self::from_pem(&pem)
    }

    /// Get the raw DER bytes.
    pub fn as_der(&self) -> &[u8] {
        &self.0
    }
}

/// Chain of certificates (leaf + intermediates).
#[derive(Clone)]
pub struct CertificateChain(pub(crate) Vec<Certificate>);

impl CertificateChain {
    /// Create from a list of certificates.
    pub fn new(certs: Vec<Certificate>) -> Self {
        CertificateChain(certs)
    }

    /// Load from PEM file.
    pub fn from_pem_file(path: impl AsRef<Path>) -> Result<Self, TlsError> {
        Ok(CertificateChain(Certificate::from_pem_file(path)?))
    }

    /// Get the certificates.
    pub fn certs(&self) -> &[Certificate] {
        &self.0
    }
}

/// Private key.
pub struct PrivateKey(pub(crate) Vec<u8>);

impl PrivateKey {
    /// Parse a private key from PEM data.
    ///
    /// Supports PKCS#8 and PKCS#1 (RSA) formats.
    pub fn from_pem(pem: &[u8]) -> Result<Self, TlsError> {
        let mut reader = std::io::BufReader::new(pem);

        // Try PKCS#8 first
        let keys = rustls_pemfile::pkcs8_private_keys(&mut reader)
            .map_err(|e| TlsError::Certificate(e.to_string()))?;

        if let Some(key) = keys.into_iter().next() {
            tracing::debug!("Parsed PKCS#8 private key");
            return Ok(PrivateKey(key.secret_pkcs8_der().to_vec()));
        }

        // Try RSA
        let mut reader = std::io::BufReader::new(pem);
        let keys = rustls_pemfile::rsa_private_keys(&mut reader)
            .map_err(|e| TlsError::Certificate(e.to_string()))?;

        if let Some(key) = keys.into_iter().next() {
            tracing::debug!("Parsed RSA private key");
            return Ok(PrivateKey(key.secret_pkcs1_der().to_vec()));
        }

        // Try EC
        let mut reader = std::io::BufReader::new(pem);
        let keys = rustls_pemfile::ec_private_keys(&mut reader)
            .map_err(|e| TlsError::Certificate(e.to_string()))?;

        if let Some(key) = keys.into_iter().next() {
            tracing::debug!("Parsed EC private key");
            return Ok(PrivateKey(key.secret_sec1_der().to_vec()));
        }

        Err(TlsError::Certificate("no private key found in PEM".into()))
    }

    /// Create from DER data.
    pub fn from_der(der: &[u8]) -> Self {
        PrivateKey(der.to_vec())
    }

    /// Load from PEM file.
    pub fn from_pem_file(path: impl AsRef<Path>) -> Result<Self, TlsError> {
        let pem = std::fs::read(path.as_ref())
            .map_err(|e| TlsError::Certificate(format!("reading file: {}", e)))?;
        Self::from_pem(&pem)
    }
}

/// Root certificate store.
pub struct RootCertStore {
    pub(crate) roots: rustls::RootCertStore,
}

impl RootCertStore {
    /// Create an empty store.
    pub fn empty() -> Self {
        RootCertStore {
            roots: rustls::RootCertStore::empty(),
        }
    }

    /// Add a certificate.
    pub fn add(&mut self, cert: &Certificate) -> Result<(), TlsError> {
        self.roots.add(&rustls::Certificate(cert.0.clone()))
            .map_err(|e| TlsError::Certificate(e.to_string()))
    }

    /// Add certificates from a PEM file.
    pub fn add_pem_file(&mut self, path: impl AsRef<Path>) -> Result<usize, TlsError> {
        let certs = Certificate::from_pem_file(path)?;
        let count = certs.len();

        for cert in certs {
            self.add(&cert)?;
        }

        Ok(count)
    }

    /// Get the number of root certificates.
    pub fn len(&self) -> usize {
        self.roots.len()
    }

    /// Check if empty.
    pub fn is_empty(&self) -> bool {
        self.roots.is_empty()
    }
}
