        info!("Testing TlsAcceptor with optional client auth");
        let mut roots = RootCertStore::empty();
        for cert in Certificate::from_pem(TEST_CERT_PEM).unwrap() {
            roots.add(&cert).ok();
        }

        let _acceptor = TlsAcceptorBuilder::new(test_chain(), test_key())
            .optional_client_auth(roots)
            .build()
            .unwrap();
    }

