        let acceptor = TlsAcceptorBuilder::new(test_chain(), test_key())
            .build()
            .unwrap();

        let start = std::time::Instant::now();
        for _ in 0..10000 {
            let _clone = acceptor.clone();
        }
        let elapsed = start.elapsed();

        debug!(elapsed_us = elapsed.as_micros(), "10000 clones");
