        for cert in &certs {
            store.add(cert).ok(); // May fail for non-CA certs
        }

        debug!(count = store.len(), "Added root certificates");
    }

    #[tokio::test]
    async fn test_accept_handshake_loopback() {
        info!("Testing TLS handshake on loopback");

        let acceptor = TlsAcceptorBuilder::new(test_chain(), test_key())
            .build()
            .unwrap();

        let connector = TlsConnectorBuilder::new()
            .add_root_certificates(Certificate::from_pem(TEST_CERT_PEM).unwrap())
            .build()
            .unwrap();

        // Create a duplex stream
        let (client, server) = tokio::io::duplex(8192);

        // Server accept task
        let server_task = tokio::spawn(async move {
            acceptor.accept(server).await
        });

        // Client connect task
        let client_task = tokio::spawn(async move {
            connector.connect("localhost", client).await
        });

        let (server_result, client_result) = tokio::join!(server_task, client_task);

        // Both should succeed
        let _server_stream = server_result.unwrap().unwrap();
        let _client_stream = client_result.unwrap().unwrap();

        info!("Loopback TLS handshake succeeded");
    }
