/// Container for I/O events returned by poll().
///
/// Re-use across poll() calls to avoid allocation.
#[derive(Debug)]
pub struct Events {
    events: Vec<Event>,
    capacity: usize,
}

/// A single I/O event.
#[derive(Debug, Clone, Copy)]
pub struct Event {
    /// Token identifying the source.
    pub token: Token,
    /// Readiness flags that triggered.
    pub ready: Interest,
}

impl Events {
    /// Create with given capacity.
    pub fn with_capacity(capacity: usize) -> Self {
        Self {
            events: Vec::with_capacity(capacity),
            capacity,
        }
    }

    /// Clear events, maintaining capacity.
    pub fn clear(&mut self) {
        self.events.clear();
    }

    /// Push a new event.
    pub fn push(&mut self, event: Event) {
        // Don't exceed capacity
        if self.events.len() < self.capacity {
            self.events.push(event);
        }
    }

    /// Number of events.
    pub fn len(&self) -> usize {
        self.events.len()
    }

    /// Check if empty.
    pub fn is_empty(&self) -> bool {
        self.events.is_empty()
    }

    /// Iterate over events.
    pub fn iter(&self) -> impl Iterator<Item = &Event> {
        self.events.iter()
    }

    /// Capacity.
    pub fn capacity(&self) -> usize {
        self.capacity
    }
}

impl<'a> IntoIterator for &'a Events {
    type Item = &'a Event;
    type IntoIter = std::slice::Iter<'a, Event>;

    fn into_iter(self) -> Self::IntoIter {
        self.events.iter()
    }
}
